const now = new Date();
const tw = new Date(now.getTime() + 8 * 3600 * 1000);
const yyyy = tw.getUTCFullYear();
const mm = String(tw.getUTCMonth() + 1).padStart(2, '0');
const dd = String(tw.getUTCDate()).padStart(2, '0');
const isoDate  = `${yyyy}-${mm}-${dd}`;
const dateSlug = `${yyyy}_${mm}_${dd}`;
const xlsName  = `${dateSlug}.xls`;
const xlsUrl   = `https://www.taoyuan-airport.com/uploads/fos/${xlsName}`;
return [{ json: { isoDate, dateSlug, xlsUrl, xlsName, fileExt: 'xls' } }];

const item = $input.first();
const binary = item.binary;

if (!binary?.data) {
  throw new Error('下載失敗：未收到 Binary 資料（官網可能阻擋請求或檔案不存在）。');
}

const mimeType = (binary.data.mimeType || '').toLowerCase();
const fileName = (binary.data.fileName  || '').toLowerCase();
const fileSize = binary.data.fileSize   || 0;
const xlsUrl   = $('計算日期').first().json.xlsUrl;

if (mimeType.includes('text/html') || mimeType.includes('text/plain') || mimeType.includes('application/json')) {
  throw new Error(
    `[MIME 錯誤] 伺服器回傳 "${mimeType}" 而非 Excel 檔案（${fileSize} bytes）。\nURL: ${xlsUrl}`
  );
}

if (fileSize < 2000) {
  throw new Error(`檔案過小 (${fileSize} bytes)，可能為錯誤頁面或 404。URL: ${xlsUrl}`);
}

let detectedFormat = 'xls';
if (mimeType.includes('openxmlformats') || fileName.endsWith('.xlsx')) {
  detectedFormat = 'xlsx';
}

console.log(`[n8n] ✅ Binary OK | size=${fileSize} | mime=${mimeType} | format=${detectedFormat}`);
return [{ json: { ...item.json, detectedFormat }, binary: item.binary }];

const items = $input.all();

// XLS 第一列是「報表產出時間：YYYY-MM-DD HH:mm:ss」作為 header key（每天不同）
// 動態找出哪個欄位的值包含 ≥20 個 0-23 的整數 → 即「時段」欄
function findHourKey(rows) {
  if (!rows.length) return null;
  const keys = Object.keys(rows[0].json);
  for (const key of keys) {
    const hits = rows.filter(r => {
      const v = parseInt(String(r.json[key] ?? ''), 10);
      return !isNaN(v) && v >= 0 && v <= 23;
    }).length;
    if (hits >= 20) return key;
  }
  return null;
}

// 根據 XLS 欄位結構：
//   __EMPTY   = 總計-入境（第 1 個空格欄）
//   __EMPTY_1 = 總計-出境（第 2 個空格欄）
const COL_ARR = '__EMPTY';
const COL_DEP = '__EMPTY_1';

const hourKey = findHourKey(items);
if (!hourKey) throw new Error('無法找到時段欄位，XLS 格式可能已變更');

const hours = [];
for (const item of items) {
  const row = item.json;
  const hour = parseInt(String(row[hourKey] ?? ''), 10);
  if (isNaN(hour) || hour < 0 || hour > 23) continue;

  hours.push({
    hour,
    forecastCount: (Number(row[COL_ARR]) || 0) + (Number(row[COL_DEP]) || 0),
    terminal: 'all',
  });
}

const filled = Array.from({ length: 24 }, (_, h) =>
  hours.find(r => r.hour === h) ?? { hour: h, forecastCount: 0, terminal: 'all' }
);

const { isoDate, xlsName } = $('計算日期').first().json;
return [{ json: { date: isoDate, sourceFile: xlsName, hours: filled } }];

const d = $input.first().json;
const date = d.data?.date || d.date || '?';
const peak = d.data?.peakHour ?? '?';
const total = d.data?.totalForecast ?? '?';
return [{ json: { ok: true, date, peakHour: peak, totalForecast: total, raw: d } }];
